#include <bits/stdc++.h>
using namespace std;

const int N=55,mod=353442899;

int n,m,t,c[N],f[N][N],g[N][N][N],tmp[N][N],sz[N],ans;
bool b[N][N];
vector<int> e[N];

void dfs1(int x,int fa){
    for(int i=1;i<=m;i++)
        f[x][i]=1;
    for(int y:e[x])
        if(y!=fa){
            dfs1(y,x);
            for(int i=1;i<=m;i++){
                int sum=0;
                for(int j=1;j<=m;j++)
                    if(!b[i][j])
                        sum=(sum+f[y][j])%mod;
                f[x][i]=1LL*f[x][i]*sum%mod;
            }
        }
}

void dfs2(int x,int fa,int tp){
    sz[x]=1;
    for(int i=1;i<=m;i++)
        g[x][i][i==tp]=1;
    for(int y:e[x])
        if(y!=fa){
            dfs2(y,x,tp);
            memset(tmp,0,sizeof(tmp));
            for(int i=1;i<=m;i++)
                for(int j=1;j<=m;j++){
                    if(b[i][j])
                        continue;
                    for(int k=(i==tp);k<=sz[x]-(i!=tp);k++)
                        for(int l=(j==tp);l<=sz[y]-(j!=tp);l++)
                            tmp[i][k+l]=(tmp[i][k+l]+1LL*g[x][i][k]*g[y][j][l])%mod;
                }
            sz[x]+=sz[y];
            for(int i=1;i<=m;i++)
                for(int j=0;j<=n;j++)
                    g[x][i][j]=tmp[i][j];
        }
}

int main(){
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=m;i++)
        scanf("%d",&c[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    while(t--){
        int u,v;
        scanf("%d%d",&u,&v);
        b[u][v]=1;
    }
    dfs1(1,0);
    for(int i=1;i<=m;i++)
        ans=(ans+f[1][i])%mod;
    for(int i=1;i<=m;i++){
        memset(g,0,sizeof(g));
        dfs2(1,0,i);
        for(int j=1;j<=m;j++)
            for(int k=c[i]+1;k<=n;k++)
                ans=(ans-g[1][j][k])%mod;
    }
    printf("%d",(ans+mod)%mod);
    return 0;
}
